import{_ as e,O as r,H as l,f as o,k as i,i as n}from"./chunks/framework.Pt2pSV98.js";const g=JSON.parse('{"title":"参数 (Parameters)","description":"模型在训练中学到的\\"知识权重\\"——参数越多通常能力越强，但不是唯一指标","frontmatter":{"title":"参数 (Parameters)","description":"模型在训练中学到的\\"知识权重\\"——参数越多通常能力越强，但不是唯一指标","difficulty":"beginner"},"headers":[],"relativePath":"terms/parameters.md","filePath":"terms/parameters.md"}'),s={name:"terms/parameters.md"};function d(h,t,u,m,c,p){const a=r("DifficultyBadge");return l(),o("div",null,[i(a,{level:"beginner"}),t[0]||(t[0]=n('<h1 id="参数-parameters" tabindex="-1">参数 (Parameters) <a class="header-anchor" href="#参数-parameters" aria-label="Permalink to &quot;参数 (Parameters)&quot;">​</a></h1><p>当你看到 &quot;GPT-4 有 1.7 万亿参数&quot; &quot;Llama 3 有 70B 参数&quot; 这样的数字时，它们到底是什么意思？</p><h2 id="一句话解释" tabindex="-1">一句话解释 <a class="header-anchor" href="#一句话解释" aria-label="Permalink to &quot;一句话解释&quot;">​</a></h2><p>参数（Parameters）是模型在训练过程中学到的一组数值——就好比人脑中神经元的连接强度。这些数值决定了输入数据经过模型后会产生什么输出。参数越多，模型通常越 &quot;聪明&quot;，但训练和运行成本也越高。</p><h2 id="通俗类比" tabindex="-1">通俗类比 <a class="header-anchor" href="#通俗类比" aria-label="Permalink to &quot;通俗类比&quot;">​</a></h2><p>把模型想象成一个<strong>超级多按钮的调音台</strong>：</p><ul><li>每个参数 = 调音台上的一个小旋钮</li><li>训练过程 = 一位专业调音师花几个月时间，反复播放各种音乐，每次微调所有旋钮，直到音效完美</li><li>推理过程 = 用调好的旋钮位置直接播放，不再调整</li></ul><p>70 亿参数（7B）的模型，相当于有 <strong>70 亿个旋钮</strong>需要调——这就是为什么训练大模型需要天价计算资源。</p><h2 id="技术定义" tabindex="-1">技术定义 <a class="header-anchor" href="#技术定义" aria-label="Permalink to &quot;技术定义&quot;">​</a></h2><p>参数在神经网络中以<strong>矩阵形式</strong>存储，通常是浮点数（FP16、FP32 等）：</p><ul><li><strong>参数量级</strong>：7B（70 亿）、70B（700 亿）、数百 B（数千亿）、万亿+</li><li><strong>存储估算</strong>：1 个参数如果用 FP16（2 字节），7B 模型大约占 <strong>14GB 显存</strong>（仅参数，不含推理开销）</li><li><strong>算力需求</strong>：参数量翻倍 ≈ 推理算力翻倍</li></ul><p>参数数量 ≠ 一切。以下是影响模型能力的核心要素：</p><table tabindex="0"><thead><tr><th>因素</th><th>说明</th></tr></thead><tbody><tr><td>参数数量</td><td>模型的 &quot;容量&quot;，越高理论上能学更多</td></tr><tr><td>训练数据质量</td><td>垃圾数据训练不出好模型</td></tr><tr><td>训练数据量</td><td>参数多但数据少 = 过拟合</td></tr><tr><td>架构设计</td><td>MoE 架构可让部分参数 &quot;休眠&quot;，降低推理成本</td></tr><tr><td>后训练优化</td><td>RLHF、DPO 等对齐技术对实际体验影响巨大</td></tr></tbody></table><h2 id="关联术语" tabindex="-1">关联术语 <a class="header-anchor" href="#关联术语" aria-label="Permalink to &quot;关联术语&quot;">​</a></h2><ul><li><a href="/ai-knowledge/terms/training-inference.html">训练 / 推理</a> —— 参数在训练中更新，在推理中固定</li><li><a href="/ai-knowledge/terms/llm.html">大语言模型 (LLM)</a> —— LLM 通常参数量大</li></ul><h2 id="快速记忆" tabindex="-1">快速记忆 <a class="header-anchor" href="#快速记忆" aria-label="Permalink to &quot;快速记忆&quot;">​</a></h2><p>参数量好比模型的脑细胞数量。7B ≈ 聪明大学生，70B ≈ 院士，但更多参数 ≠ 更聪明，还要看训练数据质量。</p><h2 id="延伸阅读" tabindex="-1">延伸阅读 <a class="header-anchor" href="#延伸阅读" aria-label="Permalink to &quot;延伸阅读&quot;">​</a></h2><ul><li><a href="https://arxiv.org/abs/2001.08361" target="_blank" rel="noreferrer">Scaling Laws for Neural Language Models</a> —— 参数、数据、算力的关系</li><li><a href="https://arxiv.org/abs/2203.15556" target="_blank" rel="noreferrer">Chinchilla 缩放定律</a> —— 多少参数配多少数据最优</li></ul>',19))])}const b=e(s,[["render",d]]);export{g as __pageData,b as default};
